[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
@page { size: A4; margin: 10mm; }
.print-format { font-family: Arial, Helvetica, sans-serif; font-size: 10px; color: #222; }
table { width: 100%; border-collapse: collapse; border-spacing: 0; }
.title { text-align: center; font-size: 16px; font-weight: bold; letter-spacing: 1px; margin-bottom: 8px; }
.header-table td, .ingredient-table th, .ingredient-table td, .sign-table td { border: 1px solid #999; padding: 5px 6px; vertical-align: top; }
.header-table .label { width: 18%; font-weight: bold; background: #eee; }
.header-table .value { width: 32%; }
.ingredient-table { margin-top: 10px; table-layout: fixed; }
.ingredient-table th { background: #e6e6e6; font-weight: bold; text-align: left; }
.sn { width: 5%; text-align: center; }
.ingredient { width: 22%; word-wrap: break-word; }
.qty { width: 11%; word-wrap: break-word; }
.batch { width: 13%; word-wrap: break-word; }
.ar { width: 13%; word-wrap: break-word; }
.blank { width: 13%; min-width: 22mm; }
.muted { color: #666; font-size: 8px; }
.warning { border: 1px solid #777; padding: 7px; margin-top: 8px; font-weight: bold; text-align: center; }
.sign-table { margin-top: 18px; table-layout: fixed; page-break-inside: avoid; }
.sign-title { font-weight: bold; text-align: center; margin-bottom: 8px; }
.line { border-bottom: 1px solid #777; height: 16px; margin-bottom: 4px; }
.batch-line { display: block; margin-bottom: 2px; }
</style>
{% set ctx = frappe.get_attr("pharma_manufacturing_mgmt.utils.print_context.get_dispensing_sheet_context")(doc.name) %}
<div class="title">RAW MATERIAL DISPENSING / WEIGHING SHEET</div>
<table class="header-table">
<tbody>
<tr>
<td class="label">Product</td><td class="value">{{ ctx.product }}</td>
<td class="label">Work Order</td><td class="value">{{ ctx.work_order }}</td>
</tr>
<tr>
<td class="label">Batch Size</td><td class="value">{{ ctx.batch_size }}</td>
<td class="label">FG Batch No.</td><td class="value">{{ ctx.fg_batch_no }}</td>
</tr>
{% if ctx.party %}
<tr><td class="label">Party / Marketed By</td><td class="value" colspan="3">{{ ctx.party }}</td></tr>
{% endif %}
<tr>
<td class="label">Posting Date</td><td class="value">{{ ctx.posting_date }}</td>
<td class="label">Stock Entry No.</td><td class="value">{{ ctx.stock_entry }}</td>
</tr>
</tbody>
</table>
<table class="ingredient-table">
<thead>
<tr>
<th class="sn">S.N.</th>
<th class="ingredient">Ingredient</th>
<th class="qty">Std. Qty</th>
<th class="qty">Issued Qty</th>
<th class="batch">Batch No.(s)</th>
<th class="ar">A.R. No.</th>
<th class="blank">Weighed By</th>
<th class="blank">Checked By</th>
</tr>
</thead>
<tbody>
{% for ingredient in ctx.ingredients %}
<tr>
<td class="sn">{{ loop.index }}</td>
<td class="ingredient">{{ ingredient.item_name }}<br><span class="muted">{{ ingredient.item_code }}</span></td>
<td class="qty">{{ ingredient.standard_qty }}</td>
<td class="qty">{{ ingredient.issued_qty }}</td>
<td class="batch">
{% if ingredient.batches %}
    {% for batch in ingredient.batches %}<span class="batch-line">{{ batch.batch_no }}</span>{% endfor %}
{% else %}
    —
{% endif %}
</td>
<td class="ar">
{% if ingredient.batches %}
    {% for batch in ingredient.batches %}<span class="batch-line">{{ batch.ar_number }}</span>{% endfor %}
{% else %}
    —
{% endif %}
</td>
<td class="blank">&nbsp;</td>
<td class="blank">&nbsp;</td>
</tr>
{% endfor %}
{% if not ctx.ingredients %}
<tr><td colspan="8" style="text-align:center; color:#777;">No consumed material rows found.</td></tr>
{% endif %}
</tbody>
</table>
<div class="warning">DO NOT DISPENSE RAW MATERIAL WITHOUT QC APPROVAL — SYSTEM ENFORCED</div>
<table class="sign-table">
<tr>
<td><div class="sign-title">Prepared By (Stores)</div><div>Name</div><div class="line"></div><div>Sign</div><div class="line"></div><div>Date / Time</div><div class="line"></div></td>
<td><div class="sign-title">Checked By (Mfg)</div><div>Name</div><div class="line"></div><div>Sign</div><div class="line"></div><div>Date / Time</div><div class="line"></div></td>
<td><div class="sign-title">Approved By (QC)</div><div>Name</div><div class="line"></div><div>Sign</div><div class="line"></div><div>Date / Time</div><div class="line"></div></td>
</tr>
</table>"}]
